// FqlLexerTEMPLATE is the FqlLexer mode.
const FqlLexerTEMPLATE = 1

func (l *FqlLexer) Action(localctx antlr.RuleContext, ruleIndex, actionIndex int) {
	switch ruleIndex {
	case 13:
		l.OpenBrace_Action(localctx, actionIndex)

	case 14:
		l.CloseBrace_Action(localctx, actionIndex)

	case 102:
		l.TemplateExprStart_Action(localctx, actionIndex)

	default:
		panic("No registered action for: " + fmt.Sprint(ruleIndex))
	}
}

func (l *FqlLexer) OpenBrace_Action(localctx antlr.RuleContext, actionIndex int) {
	switch actionIndex {
	case 0:
		if len(l.templateDepth) > 0 {
			l.templateDepth[len(l.templateDepth)-1]++
		}

	default:
		panic("No registered action for: " + fmt.Sprint(actionIndex))
	}
}
func (l *FqlLexer) CloseBrace_Action(localctx antlr.RuleContext, actionIndex int) {
	switch actionIndex {
	case 1:

		if len(l.templateDepth) > 0 {
			l.templateDepth[len(l.templateDepth)-1]--
			if l.templateDepth[len(l.templateDepth)-1] == 0 {
				l.templateDepth = l.templateDepth[:len(l.templateDepth)-1]
				l.PopMode()
				l.SetType(FqlLexerTemplateExprEnd)
			}
		}

	default:
		panic("No registered action for: " + fmt.Sprint(actionIndex))
	}
}
func (l *FqlLexer) TemplateExprStart_Action(localctx antlr.RuleContext, actionIndex int) {
	switch actionIndex {
	case 2:

		l.templateDepth = append(l.templateDepth, 1)
		l.PushMode(0)

	default:
		panic("No registered action for: " + fmt.Sprint(actionIndex))
	}
}

func (l *FqlLexer) Sempred(localctx antlr.RuleContext, ruleIndex, predIndex int) bool {
	switch ruleIndex {
	case 103:
		return l.TemplateChars_Sempred(localctx, predIndex)

	default:
		panic("No registered predicate for: " + fmt.Sprint(ruleIndex))
	}
}

func (p *FqlLexer) TemplateChars_Sempred(localctx antlr.RuleContext, predIndex int) bool {
	switch predIndex {
	case 0:
		return p.GetInputStream().LA(1) != '{'

	default:
		panic("No predicate with index: " + fmt.Sprint(predIndex))
	}
}
